import React, { useState, useEffect } from 'react';
import api from '../../services/api';

const EnhancedStoreListing = () => {
  const [stores, setStores] = useState([]);
  const [categories, setCategories] = useState([]);
  const [filters, setFilters] = useState({
    search: '',
    category: '',
    minRating: 0,
    sortBy: 'rating'
  });
  const [viewMode, setViewMode] = useState('grid');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchStores();
    fetchCategories();
  }, [filters]);

  const fetchStores = async () => {
    setLoading(true);
    setError(null);
    try {
      const params = new URLSearchParams();
      if (filters.search) params.append('search', filters.search);
      if (filters.category) params.append('category', filters.category);
      if (filters.minRating) params.append('minRating', filters.minRating);
      if (filters.sortBy) params.append('sortBy', filters.sortBy);
      
      const response = await api.get(`/stores?${params}`);
      
      // Ensure all stores have proper numeric values
      const processedStores = response.data.map(store => ({
        ...store,
        overall_rating: parseFloat(store.overall_rating) || 0,
        total_ratings: parseInt(store.total_ratings) || 0
      }));
      
      setStores(processedStores);
    } catch (error) {
      console.error('Failed to fetch stores:', error);
      setError('Failed to load stores. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const response = await api.get('/stores/categories');
      setCategories(response.data);
    } catch (error) {
      console.error('Failed to fetch categories:', error);
      // Use default categories if API fails
      setCategories([
        { id: 1, name: 'Grocery', icon: '🛒' },
        { id: 2, name: 'Electronics', icon: '📱' },
        { id: 3, name: 'Fashion', icon: '👕' },
        { id: 4, name: 'Restaurant', icon: '🍔' },
        { id: 5, name: 'Coffee Shop', icon: '☕' },
        { id: 6, name: 'Bookstore', icon: '📚' },
        { id: 7, name: 'Pharmacy', icon: '💊' },
        { id: 8, name: 'Fitness', icon: '💪' }
      ]);
    }
  };

  const handleFilterChange = (key, value) => {
    setFilters({ ...filters, [key]: value });
  };

  // Safe function to get rating value
  const getRatingValue = (rating) => {
    if (rating === null || rating === undefined) return 0;
    const num = parseFloat(rating);
    return isNaN(num) ? 0 : num;
  };

  const StoreCard = ({ store }) => {
    const avgRating = getRatingValue(store.overall_rating);
    const totalRatings = store.total_ratings || 0;
    
    return (
      <div className="enhanced-store-card">
        <div className="store-image-section">
          <img 
            src={store.image || '/default-store.jpg'} 
            alt={store.name}
            onError={(e) => {
              e.target.src = '/default-store.jpg';
            }}
          />
          <div className="store-rating-badge">
            {avgRating > 0 ? avgRating.toFixed(1) : 'New'} ★
          </div>
          {store.category && (
            <div className="store-category-badge">{store.category}</div>
          )}
        </div>
        <div className="store-info-section">
          <h3>{store.name || 'Unnamed Store'}</h3>
          <div className="store-address">
            📍 {store.address || 'Address not available'}
          </div>
          <div className="store-stats">
            <span>⭐ {avgRating > 0 ? avgRating.toFixed(1) : 'No ratings'}</span>
            <span>📊 {totalRatings} {totalRatings === 1 ? 'review' : 'reviews'}</span>
          </div>
          {store.description && (
            <p className="store-description">
              {store.description.substring(0, 100)}
              {store.description.length > 100 ? '...' : ''}
            </p>
          )}
          <button 
            className="btn btn-primary"
            onClick={() => window.location.href = `/store/${store.id}`}
          >
            View Details
          </button>
        </div>
      </div>
    );
  };

  const StoreListItem = ({ store }) => {
    const avgRating = getRatingValue(store.overall_rating);
    const totalRatings = store.total_ratings || 0;
    
    return (
      <div className="enhanced-store-list-item">
        <img 
          src={store.image || '/default-store.jpg'} 
          alt={store.name}
          width="80" 
          height="80"
          onError={(e) => {
            e.target.src = '/default-store.jpg';
          }}
        />
        <div className="list-item-info">
          <h4>{store.name || 'Unnamed Store'}</h4>
          <p>{store.address || 'Address not available'}</p>
          <div className="store-rating">
            <span>⭐ {avgRating > 0 ? avgRating.toFixed(1) : 'No ratings'}</span>
            <span>({totalRatings} {totalRatings === 1 ? 'review' : 'reviews'})</span>
          </div>
        </div>
        <button 
          className="btn btn-primary"
          onClick={() => window.location.href = `/store/${store.id}`}
        >
          Rate Store
        </button>
      </div>
    );
  };

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>Loading stores...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error-container">
        <p>{error}</p>
        <button className="btn btn-primary" onClick={fetchStores}>
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="enhanced-store-listing">
      <div className="hero-section">
        <h1>Discover Great Stores</h1>
        <p>Find the best places to shop in your area</p>
      </div>

      <div className="filters-section">
        <div className="search-bar">
          <input
            type="text"
            placeholder="Search by store name or address..."
            value={filters.search}
            onChange={(e) => handleFilterChange('search', e.target.value)}
          />
        </div>

        <div className="filter-controls">
          <select 
            value={filters.category} 
            onChange={(e) => handleFilterChange('category', e.target.value)}
          >
            <option value="">All Categories</option>
            {categories.map(cat => (
              <option key={cat.id} value={cat.name}>
                {cat.icon || '📌'} {cat.name}
              </option>
            ))}
          </select>

          <select 
            value={filters.minRating} 
            onChange={(e) => handleFilterChange('minRating', e.target.value)}
          >
            <option value="0">All Ratings</option>
            <option value="4">4+ Stars</option>
            <option value="3">3+ Stars</option>
            <option value="2">2+ Stars</option>
          </select>

          <select 
            value={filters.sortBy} 
            onChange={(e) => handleFilterChange('sortBy', e.target.value)}
          >
            <option value="rating">Highest Rated</option>
            <option value="reviews">Most Reviews</option>
            <option value="name">Name A-Z</option>
          </select>

          <div className="view-toggle">
            <button 
              className={viewMode === 'grid' ? 'active' : ''} 
              onClick={() => setViewMode('grid')}
            >
              📱 Grid
            </button>
            <button 
              className={viewMode === 'list' ? 'active' : ''} 
              onClick={() => setViewMode('list')}
            >
              📋 List
            </button>
          </div>
        </div>
      </div>

      {stores.length === 0 ? (
        <div className="no-results">
          <p>No stores found matching your criteria</p>
        </div>
      ) : (
        <div className={viewMode === 'grid' ? 'stores-grid' : 'stores-list'}>
          {stores.map(store => (
            viewMode === 'grid' 
              ? <StoreCard key={store.id} store={store} />
              : <StoreListItem key={store.id} store={store} />
          ))}
        </div>
      )}
    </div>
  );
};

export default EnhancedStoreListing;
